var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_QM","text":{"KOREA":"실례합니다. 강소영 경위님이 여기 입원해 계신다고 하던데요.","JPN":"失礼します。マエカワ・ナツミ警部補がここに入院してると聞いて来たのですが。","ENG":"Excuse me. Is this Lieutenant Kang Soyoung's room?","TWN":"不好意思，我聽說姜素英警官在這間醫院裡？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그렇습니다만…. 누구시죠?","JPN":"そうですけど……あなたは？","ENG":"Yes... And you are?","TWN":"是沒錯…不過你是哪位？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"아, 그저 최근에 경위님께 도움을 받은 사람입니다.","JPN":"あ、この前警部補に助けてもらった者です。","ENG":"Oh, I'm just someone she helped recently.","TWN":"姜素英警官最近曾經幫助過我。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"최근에……?","JPN":"この前……？","ENG":"Recently...?","TWN":"最近……？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이상하네요. 최근에는 저와 같이 다니느라 따로 누굴 도울 틈 따윈 없었을 텐데.","JPN":"おかしいですね。警部補はここのところ常に私と一緒に行動していて、誰かを助けられる時間はなかったはずですが。","ENG":"That's odd. The lieutenant was with me for the past few days, so she couldn't have had the time to help anyone else.","TWN":"這麼奇怪？她最近都跟我一起行動，應該沒多餘的時間可以去幫助人吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그러고 보니 낯이 익은 것 같기도 하고…… 우리 어디서 만난 적 있었나요?","JPN":"そういえば見覚えがあるような……どこかでお会いしたことがありますか？","ENG":"But you do look familiar... Have we met before?","TWN":"而且我對你的臉也沒印象……我們有在哪見過嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"이렇게 사람이 많은 도시에 살다 보면 마주쳤을지도 모르지요.","JPN":"これだけ人が多い都市に住んでいると、出くわしたこともあるかもしれません。","ENG":"In a city with this many people, we may have crossed paths once before.","TWN":"在這人滿為患的城市裡生活，或許曾經有過一面之緣吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"인연이 닿은 어딘가에서, 혹은 기억나지 않는 어린 시절의 언젠가에서.","JPN":"縁のある場所で、あるいは思い出せないほど幼い頃のある時に。","ENG":"Perhaps we met somewhere on the streets, or a long time ago in the past.","TWN":"可能曾經在某個地方見過，或是小時候見過，只是現在想不起來。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"너무 경계하실 필요 없습니다. 전 그저 꽃을 전해주러 왔을 뿐이니까요.","JPN":"そんなに構えないでください。私はただお花を届けに来ただけです。  ","ENG":"There's no need to be alarmed. I am just here to give her this flower.","TWN":"你不需要這麼有戒心，我只是來送花的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"도움을 받으면 감사를 표하는 것이 예의라고 아버지께 배웠거든요.","JPN":"助けてもらったら感謝の気持ちを伝えるのが礼儀だと、父から教わったものですから。","ENG":"I learned from my Father to always express gratitude to those who have helped me.","TWN":"爸爸教導我，受人點滴當湧泉以報。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"설령 도움을 준 사람이 그 사실을 모르고, 의도치 않았다고 해도 말이지요.","JPN":"たとえ助けてくれた人がその事実を知らず、意図していなかったとしてもね。","ENG":"Even if that person doesn't know it, or didn't intend to do so.","TWN":"就算那個人是無意中幫助到人，他本身並不知情也是一樣。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……처음 보는 건데, 무슨 꽃이죠?","JPN":"……初めて見る花ですが、何ですか？","ENG":"…Never seen this before. What kind of flower is it?","TWN":"……這是什麼花，我還是第一次看到呢？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"베로니카입니다.","JPN":"ベロニカです。","ENG":"It's Veronica.","TWN":"Veronica(鼠尾草)，"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"꽃말은 충실이라고 하더군요.","JPN":"花言葉は忠実だそうです。","ENG":"It symbolizes \\"loyalty\\".","TWN":"花語是忠誠。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"베로니카…….","JPN":"ベロニカ……","ENG":"Veronica...","TWN":"Veronica(音同貝洛妮卡)……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_QM","text":{"KOREA":"그나저나 강소영 경위님의 상태는 어떤가요?","JPN":"それより、マエカワ・ナツミ警部補の具合はどうですか？","ENG":"Anyway, how is Lieutenant Kang's condition?","TWN":"話說回來，姜素英警官的身體還好嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SYSOP_EP9HALF_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};